sql:
SELECT run_id, MAX(max_oob_percentage) AS max_oob_percentage
FROM vehicle_state
GROUP BY run_id;

SELECT AVG(vel_kmh) AS avg_velocity
FROM simulation_data
WHERE run_id = 1;

SELECT model_id, COUNT(run_id) AS simulation_count
FROM simulation_runs
GROUP BY model_id;

SELECT COUNT(DISTINCT run_id) AS num_runs
FROM vehicle_state
WHERE oob_percentage > 50;

SELECT pos_x, pos_y
FROM vehicle_dynamics
WHERE vel_kmh > 50;

